# ─── Error parsing ────────────────────────────────────────────────────────────

def parse_error(error_text):
    """Parse Lean error to classify failure type."""
    if 'TIMEOUT' in error_text:
        return 'timeout', {}

    err_lower = error_text.lower()

    if 'unknown identifier' in err_lower or 'unknown constant' in err_lower:
        m = re.search(r"unknown (?:identifier|constant) '([^']+)'", error_text)
        name = m.group(1) if m else ""
        return 'unknown_ident', {'name': name}

    if 'type mismatch' in err_lower:
        # Extract expected and got types
        m = re.search(r'expected\s+(.+?)(?:\n|$)', error_text)
        expected = m.group(1).strip() if m else ""
        m2 = re.search(r'(?:has type|got)\s+(.+?)(?:\n|$)', error_text)
        got = m2.group(1).strip() if m2 else ""
        return 'type_mismatch', {'expected': expected, 'got': got}

    if 'tactic' in err_lower and 'failed' in err_lower:
        return 'tactic_failed', {}

    if 'unsolved goals' in err_lower:
        # Extract remaining goal
        m = re.search(r'unsolved goals\n(.*?)(?:\n\n|$)', error_text, re.DOTALL)
        remaining = m.group(1).strip() if m else ""
        return 'unsolved_goals', {'goal': remaining}

    if 'application type mismatch' in err_lower:
        return 'app_mismatch', {}

    if 'function expected' in err_lower:
        return 'func_expected', {}

    if 'maximum recursion depth' in err_lower or 'deep recursion' in err_lower:
        return 'recursion', {}

    if 'heartbeats' in err_lower:
        return 'heartbeats', {}

    return 'other', {'text': error_text[:200]}

def error_driven_alternatives(err_type, err_info, info, prev_tactic):
    """Given an error, suggest alternative tactics."""
    alts = []

    if err_type == 'type_mismatch':
        # Try cast-related fixes
        alts.extend([
            f"push_cast; {prev_tactic}",
            f"norm_cast; {prev_tactic}",
            f"exact_mod_cast (by {prev_tactic})",
        ])

    if err_type == 'unsolved_goals':
        goal_text = err_info.get('goal', '')
        if '∧' in goal_text:
            alts.append(f"constructor <;> ({prev_tactic})")
        if '=' in goal_text:
            alts.extend([f"ring", f"linarith", f"simp_all"])
        if any(op in goal_text for op in ['<', '>', '≤', '≥']):
            alts.extend([f"linarith", f"nlinarith", f"omega"])

    if err_type == 'tactic_failed':
        # Try wrapping in simp/field_simp first
        if 'linarith' in prev_tactic or 'nlinarith' in prev_tactic:
            alts.extend([
                f"field_simp; {prev_tactic}",
                f"ring_nf; {prev_tactic}",
                f"simp_all; {prev_tactic}",
            ])
        elif 'ring' in prev_tactic:
            alts.extend(["ring_nf; ring", "simp; ring", "field_simp; ring"])

    if err_type == 'heartbeats' or err_type == 'timeout':
        # Try simpler tactics
        alts.extend(["omega", "norm_num", "ring"])

    return alts

# ─── Tactic generation (phase 1: single tactics) ─────────────────────────────

def gen_single_tactics(info):
    """Generate single-tactic attempts ordered by likely success."""
    tactics = []
    g = info['goal']
    h_list = info['h_list']
    hyps = info['hyp_names']
    vars_ = info['var_names']

    # ═══ UNIVERSAL ═══
    for t in ["omega", "norm_num", "ring", "linarith", "nlinarith",
              "simp", "simp_all", "positivity", "aesop"]:
        tactics.append((t, TIMEOUT if t != "aesop" else SLOW_TIMEOUT))

    # native_decide for finite/decidable
    if info['has_finset'] or info['has_card'] or info['has_prime'] or info['has_gcd'] or \
       info['has_mod'] or info['has_choose'] or not hyps:
        tactics.append(("native_decide", SLOW_TIMEOUT))
        tactics.append(("decide", SLOW_TIMEOUT))

    # ═══ COMPLEX ═══
    if info['has_complex']:
        if info['subst_hyps']:
            tactics.append(("subst_vars; ring", TIMEOUT))
            if info['has_and']:
                tactics.append(("constructor <;> (subst_vars; ring)", TIMEOUT))
        for c in [1, -1, 4, -4, 9, 16, 25, 49, -49]:
            tactics.append((f"ring_nf; linear_combination {c} * Complex.I_sq", TIMEOUT))
        if hyps:
            tactics.append((f"simp only [{h_list}]; ring", TIMEOUT))
            tactics.append((f"simp [Complex.ext_iff, Complex.I_sq]; constructor <;> linarith [{h_list}]", TIMEOUT))

    # ═══ SUBST ═══
    if info['subst_hyps'] and not info['has_complex']:
        for closer in ["ring", "norm_num", "omega", "linarith", "nlinarith", "simp_all"]:
            tactics.append((f"subst_vars; {closer}", TIMEOUT))
        if info['has_and']:
            for c in ["norm_num", "omega", "ring", "linarith"]:
                tactics.append((f"constructor <;> (subst_vars; {c})", TIMEOUT))

    # ═══ FORALL / FUNCTION DEF ═══
    if info['forall_hyps']:
        all_names = ", ".join([n for n, _ in info['forall_hyps']] + [n for n, _ in info['subst_hyps']])
        for closer in ["ring", "norm_num", "omega", "linarith", "nlinarith"]:
            tactics.append((f"simp only [{all_names}] at *; {closer}", TIMEOUT))
        if info['has_div']:
            tactics.append((f"simp only [{all_names}] at *; field_simp; ring", TIMEOUT))
            tactics.append((f"simp only [{all_names}] at *; field_simp; linarith", TIMEOUT))

    # ═══ CONJUNCTION ═══
    if info['has_and']:
        for c in ["omega", "norm_num", "ring", "linarith", "nlinarith", "simp", "simp_all"]:
            tactics.append((f"constructor <;> {c}", TIMEOUT))
        if hyps:
            tactics.append((f"constructor <;> linarith [{h_list}]", TIMEOUT))

